sql:
SELECT property_id, name, attribute, type, description, is_required, is_animatable, is_customizable, default_value
FROM checkbox_properties
WHERE is_required = 1;

SELECT name
FROM checkbox_properties
WHERE property_id = 0;

SELECT COUNT(*) 
FROM checkbox_components 
WHERE is_visible = 1 AND is_enabled = 1;

SELECT component_id, COUNT(DISTINCT user_id) AS unique_user_count
FROM analytics
GROUP BY component_id;

SELECT *
FROM checkbox_properties
WHERE type = 'Boolean' AND is_required = 1;

external_knowledge:
- Characteristics refer to property_id, name, attribute, and type; 
- Component counts refer to the total number of distinct components each property has; 
- Enabled and visibility ratios are calculated by dividing the number of enabled or visible components by the total number of components, assuming a value of 1 for True and 0 for False or NULL; 
- Analytics counts refer to the total number of distinct analytics events related to each property; 
- Average event durations are calculated by averaging the durations of all events related to each property.

sql:
SELECT component_name
FROM checkbox_components
WHERE theme_id = 1;

SELECT bc.component_id, bp.name
FROM checkbox_components AS bc
JOIN checkbox_properties AS bp ON bc.property_id = bp.property_id;
